const username = msg.payload?.data?.username || msg.data?.username || "";
const password = msg.payload?.data?.password || msg.data?.password || "";

if (!username || !password) {
    msg.payload = {
        response: {
            action: "login",
            status: "error",
            message: "Username and password are required."
        }
    };
    return [null, msg];
}

msg._loginUsername = username;
msg._loginPassword = password;
msg.collection = "auth_users";
msg.operation = "findOne";
msg.payload = { username: username };
return [msg, null];

const user = msg.payload;
const password = msg._loginPassword;
const username = msg._loginUsername;

if (!user) {
    msg.payload = {
        response: {
            action: "login",
            status: "error",
            message: "Invalid username or password."
        }
    };
    return [null, msg];
}

// Compare password: bcrypt hash or legacy plaintext
let valid = false;
if (user.passwordHash) {
    // bcrypt comparison
        valid = bcrypt.compareSync(password, user.passwordHash);
} else if (user.password) {
    // Legacy plaintext fallback (seeded admin only)
    valid = (password === user.password);
}

if (!valid) {
    msg.payload = {
        response: {
            action: "login",
            status: "error",
            message: "Invalid username or password."
        }
    };
    return [null, msg];
}

// Generate session token
const token = crypto.randomBytes(32).toString('hex');
const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();

msg._storeSession = true;
msg._sessionToken = token;
msg._sessionUserId = String(user._id);
msg._sessionExpiresAt = expiresAt;
msg._sessionUsername = user.username;

// Now look up dcm_users to get roles
msg.collection = "dcm_users";
msg.operation = "findOne";
msg.payload = { username: user.username };
return [msg, null];

const dcmUser = msg.payload;
const username = msg._sessionUsername;

// If no dcm_users row, auto-provision with pending status
if (!dcmUser) {
    msg._dcmUserMissing = true;
    msg._dcmRoles = [];
    msg._dcmPermissions = [];
    msg._dcmUserStatus = 'pending';
    msg._dcmUserEmail = '';
} else {
    // Block disabled accounts
    if (dcmUser.status === "disabled") {
        // Audit the blocked login attempt
        msg._auditBlockedLogin = {
            action: "login.blocked.disabled",
            targetUserId: String(dcmUser._id),
            targetUsername: dcmUser.username || username,
            at: new Date().toISOString()
        };
        msg.payload = {
            response: {
                action: "login",
                ok: false,
                status: "error",
                error: "account_disabled",
                message: "Your account is disabled. Please ask an administrator to activate it."
            }
        };
        // Write audit log then return error
        msg._disabledBlock = true;
        msg.collection = "dcm_audit_log";
        msg.operation = "insertOne";
        msg.payload = msg._auditBlockedLogin;
        return [msg, null];
    }

    // Check if account is expired
    if (dcmUser.status === 'expired' || (dcmUser.expiresAt && new Date(dcmUser.expiresAt) <= new Date())) {
        msg.payload = {
            response: {
                action: "login",
                ok: false,
                status: "error",
                error: "account_expired",
                message: "Your account has expired. Contact an administrator."
            }
        };
        return [null, msg];
    }
    msg._dcmRoles = dcmUser.roles || [];
    msg._dcmUserStatus = dcmUser.status || 'active';
    msg._dcmUserEmail = dcmUser.email || '';
    msg._dcmUserId = String(dcmUser._id);
    msg._dcmAccessAreas = dcmUser.accessAreas || [];
    msg._dcmExpiresAt = dcmUser.expiresAt || null;
}

// Now look up role permissions from dcm_roles
msg.collection = "dcm_roles";
msg.operation = "find";
msg.payload = [{ key: { $in: msg._dcmRoles } }];
return [msg, null];

// If this is a disabled-account block, audit was already written, just return error
if (msg._disabledBlock) {
    msg.payload = {
        response: {
            action: "login",
            ok: false,
            status: "error",
            error: "account_disabled",
            message: "Your account is disabled. Please ask an administrator to activate it."
        }
    };
    // Skip session creation - return directly
    return [null, msg];
}

var PERM_MAP = {
