    schemaRegistry: ["schema.registry.create", "schema.registry.read", "schema.registry.update", "schema.registry.delete"],
    adminTools: ["users.create", "users.read", "users.update", "users.delete", "roles.read", "audit.read"],
    harvest: ["harvest.run.execute", "harvest.scope.create", "harvest.scope.read", "harvest.scope.update", "harvest.scope.delete", "harvest.lifecycle.configure", "harvest.crawling.configure"]
};
function buildPermissions(accessAreas) {
    var permSet = {};
    for (var i = 0; i < accessAreas.length; i++) {
        var perms = PERM_MAP[accessAreas[i]];
        if (perms) { for (var j = 0; j < perms.length; j++) permSet[perms[j]] = true; }
    }
    return Object.keys(permSet);
}
function accessAreasToAccess(accessAreas) {
    var map = { localCatalogue: "local_catalogue", catalogueRegistry: "catalogue_registry", schemaRegistry: "schema_registry", adminTools: "admin_tools", harvest: "harvester" };
    var result = [];
    var order = ["localCatalogue","catalogueRegistry","schemaRegistry","adminTools","harvest"];
    for (var i = 0; i < order.length; i++) {
        if (accessAreas.indexOf(order[i]) >= 0) result.push(map[order[i]]);
    }
    if (result.indexOf("local_catalogue") < 0) result.unshift("local_catalogue");
    return result;
}
var roleDocs = Array.isArray(msg.payload) ? msg.payload : [];
