        for (var pi = 0; pi < roleDocs[ri].permissions.length; pi++) permSet[roleDocs[ri].permissions[pi]] = true;
    }
}
var permissions = Object.keys(permSet);
var hasWildcard = !!permSet["*"];

var rawAreas = msg._dcmAccessAreas || [];
var accessAreas;
if (hasWildcard) {
    accessAreas = accessAreasToAccess(["localCatalogue","catalogueRegistry","schemaRegistry","adminTools","harvest"]);
